{"file_path":"ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/AnnotationRuleReproductionTest.kt","content":"package com.pinterest.ktlint.ruleset.standard

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class AnnotationRuleReproductionTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }

    @Test
    fun `Given an annotation with multiple annotation entries on the same line as the annotated construct`() {
        val code =
            """
            @[JvmStatic Provides] fun foo() = 42
            """.trimIndent()
        val formattedCode =
            """
            @[JvmStatic Provides]
            fun foo() = 42
            """.trimIndent()
        annotationRuleAssertThat(code)
            .hasLintViolation(1, 1, "Annotation must be placed on separate line")
            .isFormattedAs(formattedCode)
    }
}
"}

